import { readFile } from "node:fs/promises";
import { homedir } from "node:os";
import { join } from "node:path";
import type { IngestSessionInput } from "@rudel/api-routes";
import {
	type Ingestor,
	ingestRudelCodexSessions,
	type RudelCodexSessionsRow,
} from "@rudel/ch-schema/generated";
import type {
	AgentAdapter,
	IngestContext,
	ScannedProject,
	SessionFile,
	UploadContext,
} from "../../types.js";
import {
	readJsonlFirstLine,
	toClickHouseDateTime,
	toDisplayPath,
	walkJsonlFiles,
} from "../../utils.js";
import {
	CONFIG_PATH,
	installHook,
	isHookInstalled,
	removeHook,
} from "./config.js";

const SESSIONS_BASE_DIR = join(homedir(), ".codex", "sessions");

// ── Exported utilities ──

export interface CodexSessionMeta {
	id: string;
	cwd: string;
	gitBranch?: string;
	gitSha?: string;
}

export async function readCodexSessionMeta(
	filePath: string,
): Promise<CodexSessionMeta | null> {
	const parsed = (await readJsonlFirstLine(filePath)) as {
		type?: string;
		payload?: {
			id?: string;
			cwd?: string;
			git?: { branch?: string; sha?: string };
		};
	} | null;

	if (!parsed || parsed.type !== "session_meta" || !parsed.payload) {
		return null;
	}

	return {
		id:
			parsed.payload.id ??
			filePath
				.split("/")
				.pop()
				?.replace(/\.jsonl$/, "") ??
			"",
		cwd: parsed.payload.cwd ?? "",
		gitBranch: parsed.payload.git?.branch,
		gitSha: parsed.payload.git?.sha,
	};
}

export async function findActiveRolloutFile(
	threadId: string,
): Promise<string | null> {
	const files = await walkJsonlFiles(SESSIONS_BASE_DIR);

	for (const filePath of files) {
		const meta = await readCodexSessionMeta(filePath);
		if (meta?.id === threadId) {
			return filePath;
		}
	}

	return null;
}

