45→export interface AgentAdapter {
46→	name: string;
47→	source: string;
48→	rawTableName: string;
49→
50→	// Session Discovery (CLI)
51→	getSessionsBaseDir(): string;
52→	findProjectSessions(projectPath: string): Promise<SessionFile[]>;
53→	scanAllSessions(): Promise<ScannedProject[]>;
54→
55→	// Hook Management (CLI)
