 1→import { existsSync } from "node:fs";
 2→import type { AgentAdapter } from "./types.js";
 3→
 4→const adapters = new Map<string, AgentAdapter>();
 5→
 6→export function registerAdapter(adapter: AgentAdapter): void {
 7→	adapters.set(adapter.source, adapter);
 8→}
 9→
10→export function getAdapter(source: string): AgentAdapter {
11→	const adapter = adapters.get(source);
12→	if (!adapter) {
13→		throw new Error(`No adapter registered for source: ${source}`);
14→	}
15→	return adapter;
16→}
17→
18→export function getAllAdapters(): AgentAdapter[] {
19→	return Array.from(adapters.values());
20→}
21→
22→export function getAvailableAdapters(): AgentAdapter[] {
23→	return getAllAdapters().filter((a) => existsSync(a.getSessionsBaseDir()));
24→}
