301→
302→		return {
303→			session_date: timestamps
304→				? toClickHouseDateTime(timestamps.sessionDate)
305→				: now,
306→			last_interaction_date: timestamps
307→				? toClickHouseDateTime(timestamps.lastInteractionDate)
308→				: now,
309→			session_id: input.sessionId,
310→			organization_id: context.organizationId,
311→			project_path: input.projectPath,
312→			repository: input.repository ?? null,
313→			git_remote: input.gitRemote ?? "",
314→			package_name: input.packageName ?? "",
315→			content: input.content,
316→			subagents,
317→			ingested_at: now,
318→			user_id: context.userId,
319→			git_branch: input.gitBranch ?? null,
320→			git_sha: input.gitSha ?? null,
