 46→	const spin = p.spinner();
 47→	spin.start("Scanning projects...");
 48→
 49→	const adapters = getAvailableAdapters();
 50→	const allProjects: ScannedProject[] = [];
 51→	for (const adapter of adapters) {
 52→		const projects = await adapter.scanAllSessions();
 53→		allProjects.push(...projects);
 54→	}
 55→
 56→	spin.stop(`Found ${allProjects.length} project(s)`);
 57→
 58→	if (allProjects.length === 0) {
 59→		p.log.warn("No projects with sessions found.");
 60→		p.outro("Nothing to upload.");
 61→		return;
 62→	}
 63→
 64→	const cwd = process.cwd();
 65→	const grouped = groupProjectsForCwd(allProjects, cwd);
 66→
 67→	const options: Array<{
 68→		value: ScannedProject;
 69→		label: string;
 70→		hint: string;
 71→	}> = [];
 72→	const preSelected: ScannedProject[] = [];
 73→
 74→	for (const proj of grouped.current) {
 75→		options.push({
 76→			value: proj,
 77→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 78→			hint: sessionCountHint(proj.sessionCount),
 79→		});
 80→		preSelected.push(proj);
 81→	}
 82→
 83→	for (const sub of grouped.subfolders) {
 84→		const relative = sub.projectPath.slice(cwd.length + 1);
 85→		options.push({
 86→			value: sub,
 87→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 88→			hint: sessionCountHint(sub.sessionCount),
 89→		});
 90→		preSelected.push(sub);
 91→	}
 92→
 93→	for (const other of grouped.others) {
 94→		options.push({
 95→			value: other,
 96→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
 97→			hint: sessionCountHint(other.sessionCount),
 98→		});
 99→	}
