154→		transcriptPath: w.session.transcriptPath,
155→		projectPath: w.session.projectPath,
156→		source: w.project.source,
157→		organizationId: w.organizationId,
158→		session: w.session,
159→		adapter: w.adapter,
160→		gitInfo: w.gitInfo,
161→	}));
162→
163→	const summary = await runBatchUpload({
164→		items,
165→		label: "Uploading sessions...",
166→		concurrency: flags.concurrency,
167→		upload: async (item, onRetry) => {
168→			const request = await item.adapter.buildUploadRequest(item.session, {
169→				tag: flags.tag,
170→				gitInfo: item.gitInfo,
171→				organizationId: item.organizationId,
172→			});
173→
174→			if (!flags.tag && flags.classify) {
175→				const classified = await classifySession(request.content);
176→				if (classified) {
177→					(request as { tag?: string }).tag = classified;
178→				}
179→			}
180→
181→			if (flags.dryRun) {
182→				return { success: true };
183→			}
184→
185→			return uploadSession(request, { ...uploadConfig, onRetry });
186→		},
187→	});
188→
189→	renderBatchSummary(summary, { showRetryHint: summary.failed > 0 });
190→
191→	if (flags.dryRun) {
192→		p.outro("Dry run complete — no sessions were uploaded.");
193→	} else {
194→		p.outro("Done!");
195→	}
196→
197→	if (summary.failed > 0) {
198→		process.exitCode = 1;
199→	}
200→}
