214→async function runSingleUpload(
215→	flags: UploadFlags,
216→	session: string,
217→): Promise<void> {
218→	const write = (msg: string) => {
219→		process.stdout.write(`${msg}\n`);
220→	};
221→	const writeError = (msg: string) => {
222→		process.stderr.write(`${msg}\n`);
223→	};
224→
225→	const credentials = loadCredentials();
226→	if (!credentials && !flags.dryRun) {
227→		writeError("Error: Not authenticated. Run `rudel login` first.");
228→		process.exitCode = 1;
229→		return;
230→	}
231→
232→	write(`Resolving session: ${session}`);
233→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
234→	try {
235→		sessionInfo = await resolveSession(session);
236→	} catch (error) {
237→		writeError(
238→			`Error: ${error instanceof Error ? error.message : String(error)}`,
239→		);
240→		process.exitCode = 1;
241→		return;
242→	}
243→	write(`Found session at: ${sessionInfo.transcriptPath}`);
244→
245→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
246→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
247→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
248→
249→	const organizationId =
250→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
251→	if (organizationId) write(`Organization: ${organizationId}`);
252→
253→	write("Building upload request...");
254→	const sessionFile: SessionFile = {
255→		sessionId: sessionInfo.sessionId,
256→		transcriptPath: sessionInfo.transcriptPath,
257→		projectPath: sessionInfo.projectPath,
258→	};
259→
260→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
261→		tag: flags.tag,
262→		gitInfo,
263→		organizationId,
264→	});
265→
266→	write(`Transcript: ${request.content.length} bytes`);
267→	if (request.subagents && request.subagents.length > 0) {
268→		write(`Subagents: ${request.subagents.length} file(s)`);
269→	}
270→
271→	if (!flags.tag && flags.classify) {
272→		write("Classifying session...");
273→		const classified = await classifySession(request.content);
274→		if (classified) {
275→			(request as { tag?: string }).tag = classified;
276→			write(`Classified as: ${classified}`);
277→		}
278→	}
279→
280→	if (flags.dryRun) {
281→		const preview = {
282→			...request,
283→			content: `[${request.content.length} bytes]`,
284→			subagents: request.subagents?.map((s) => ({
285→				...s,
286→				content: `[${s.content.length} bytes]`,
287→			})),
288→		};
289→		write("Dry run - would upload:");
290→		write(JSON.stringify(preview, null, 2));
291→		return;
292→	}
293→
294→	write("Uploading...");
295→	const result = await uploadSession(request, {
296→		endpoint: flags.endpoint,
297→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
298→		token: credentials!.token,
299→	});
300→
301→	if (result.success) {
302→		write("Upload successful!");
303→	} else {
304→		writeError(`Upload failed: ${result.error}`);
305→		process.exitCode = 1;
306→	}
307→}
308→
309→async function runRetryUpload(flags: UploadFlags): Promise<void> {
310→	const credentials = loadCredentials();
311→	if (!credentials) {
312→		p.log.error("Not authenticated. Run `rudel login` first.");
313→		process.exitCode = 1;
314→		return;
315→	}
316→
317→	p.intro("rudel upload --retry");
318→
319→	const failures = await loadFailedUploads();
320→	if (failures.length === 0) {
321→		p.outro("No failed uploads to retry.");
322→		return;
323→	}
324→
325→	p.log.info(`Found ${failures.length} failed upload(s):`);
326→	for (const f of failures.slice(0, 10)) {
327→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
328→	}
329→	if (failures.length > 10) {
330→		p.log.warn(`  ...and ${failures.length - 10} more`);
331→	}
332→
333→	const shouldRetry = await p.confirm({
334→		message: `Retry all ${failures.length} failed upload(s)?`,
335→		initialValue: true,
336→	});
337→
338→	if (p.isCancel(shouldRetry) || !shouldRetry) {
339→		p.cancel("Retry cancelled.");
340→		return;
341→	}
342→
343→	const endpoint = flags.endpoint;
344→
345→	type RetryItem = BatchUploadItem & {
346→		failure: (typeof failures)[number];
347→	};
348→
349→	const items: RetryItem[] = failures.map((f) => ({
350→		sessionId: f.sessionId,
351→		label: f.sessionId,
352→		transcriptPath: f.transcriptPath,
353→		projectPath: f.projectPath,
354→		source: f.source,
355→		organizationId: f.organizationId,
356→		failure: f,
357→	}));
358→
359→	const summary = await runBatchUpload({
360→		items,
361→		label: "Retrying uploads...",
362→		concurrency: flags.concurrency,
363→		upload: async (item, onRetry) => {
364→			const source = item.failure.source?.replace(/-/g, "_");
365→			const adapter = source ? getAdapter(source) : claudeCodeAdapter;
366→			const sessionFile: SessionFile = {
367→				sessionId: item.failure.sessionId,
368→				transcriptPath: item.failure.transcriptPath,
369→				projectPath: item.failure.projectPath,
370→			};
371→			const gitInfo = await getGitInfo(item.failure.projectPath);
372→			const organizationId =
373→				flags.org ??
374→				item.failure.organizationId ??
375→				(await getProjectOrgId(item.failure.projectPath));
376→
377→			const request = await adapter.buildUploadRequest(sessionFile, {
378→				tag: flags.tag,
379→				gitInfo,
380→				organizationId,
381→			});
382→
383→			return uploadSession(request, {
384→				endpoint,
385→				token: credentials.token,
386→				onRetry,
387→			});
388→		},
389→	});
390→
391→	renderBatchSummary(summary);
392→
393→	p.outro("Done!");
394→
395→	if (summary.failed > 0) {
396→		process.exitCode = 1;
397→	}
398→}
399→
400→async function runUpload(
401→	flags: UploadFlags,
402→	...sessions: string[]
403→): Promise<void> {
404→	if (flags.retry) {
405→		return runRetryUpload(flags);
406→	}
407→	if (sessions.length === 0) {
408→		return runInteractiveUpload(flags);
409→	}
410→	return runSingleUpload(flags, sessions[0] as string);
411→}
412→
