 1→import { homedir } from "node:os";
 2→import { join } from "node:path";
 3→
 4→const FAILED_UPLOADS_PATH = join(homedir(), ".rudel", "failed-uploads.json");
 5→
 6→export interface FailedUpload {
 7→	sessionId: string;
 8→	transcriptPath: string;
 9→	projectPath: string;
10→	/** Agent adapter source (e.g. "claude_code", "codex") */
11→	source?: string;
12→	organizationId?: string;
13→	error: string;
14→	failedAt: string;
15→}
16→
17→interface FailedUploadsData {
18→	failures: FailedUpload[];
19→}
20→
21→export async function loadFailedUploads(): Promise<FailedUpload[]> {
22→	try {
23→		const file = Bun.file(FAILED_UPLOADS_PATH);
24→		if (!(await file.exists())) return [];
25→		const data = (await file.json()) as FailedUploadsData;
26→		return data.failures;
27→	} catch {
28→		return [];
29→	}
30→}
31→
32→async function saveFailedUploads(failures: FailedUpload[]): Promise<void> {
33→	try {
34→		const { mkdir } = await import("node:fs/promises");
35→		const { dirname } = await import("node:path");
36→		await mkdir(dirname(FAILED_UPLOADS_PATH), { recursive: true });
37→		const data: FailedUploadsData = { failures };
38→		await Bun.write(FAILED_UPLOADS_PATH, JSON.stringify(data, null, 2));
39→	} catch {
40→		// Best-effort — don't break the upload flow
41→	}
42→}
43→
44→export async function recordFailedUpload(
45→	failure: Omit<FailedUpload, "failedAt">,
46→): Promise<void> {
47→	const failures = await loadFailedUploads();
48→	const existing = failures.findIndex((f) => f.sessionId === failure.sessionId);
49→	const entry: FailedUpload = {
50→		...failure,
51→		failedAt: new Date().toISOString(),
52→	};
53→	if (existing >= 0) {
54→		failures[existing] = entry;
55→	} else {
56→		failures.push(entry);
57→	}
58→	await saveFailedUploads(failures);
59→}
60→
61→export async function removeFailedUpload(sessionId: string): Promise<void> {
62→	const failures = await loadFailedUploads();
63→	const filtered = failures.filter((f) => f.sessionId !== sessionId);
64→	if (filtered.length !== failures.length) {
65→		await saveFailedUploads(filtered);
66→	}
67→}
