 1→import pMap from "p-map";
 2→import { recordFailedUpload, removeFailedUpload } from "./failed-uploads.js";
 3→import type { UploadResult } from "./types.js";
 4→
 5→export interface BatchUploadItem {
 6→	sessionId: string;
 7→	label: string;
 8→	transcriptPath: string;
 9→	projectPath: string;
10→	source?: string;
11→	organizationId?: string;
12→}
13→
14→export interface BatchUploadOptions<T extends BatchUploadItem> {
15→	items: T[];
16→	upload: (
17→		item: T,
18→		onRetry: (attempt: number, maxAttempts: number, error: string) => void,
19→	) => Promise<UploadResult>;
20→	concurrency?: number;
21→	onItemComplete?: (completed: number, total: number) => void;
22→	onRetry?: (
23→		label: string,
24→		attempt: number,
25→		maxAttempts: number,
26→		error: string,
27→	) => void;
28→}
29→
30→export interface BatchUploadSummary {
31→	succeeded: number;
32→	failed: number;
33→	total: number;
34→	errors: Array<{ label: string; error: string }>;
35→}
36→
37→export async function batchUpload<T extends BatchUploadItem>(
38→	options: BatchUploadOptions<T>,
39→): Promise<BatchUploadSummary> {
40→	const { items, upload, concurrency = 5, onItemComplete, onRetry } = options;
41→	const total = items.length;
42→	let succeeded = 0;
43→	let failed = 0;
44→	let completed = 0;
45→	const errors: Array<{ label: string; error: string }> = [];
46→
47→	await pMap(
48→		items,
49→		async (item) => {
50→			const itemOnRetry = (
51→				attempt: number,
52→				maxAttempts: number,
53→				error: string,
54→			) => {
55→				onRetry?.(item.label, attempt, maxAttempts, error);
56→			};
57→
58→			try {
59→				const result = await upload(item, itemOnRetry);
60→				if (result.success) {
61→					succeeded++;
62→					await removeFailedUpload(item.sessionId);
63→				} else {
64→					failed++;
65→					const error = result.error ?? "Unknown error";
66→					errors.push({ label: item.label, error });
67→					await recordFailedUpload({
68→						sessionId: item.sessionId,
69→						transcriptPath: item.transcriptPath,
70→						projectPath: item.projectPath,
71→						source: item.source,
72→						organizationId: item.organizationId,
73→						error,
74→					});
75→				}
76→			} catch (err) {
77→				failed++;
78→				const error = err instanceof Error ? err.message : String(err);
79→				errors.push({ label: item.label, error });
80→				await recordFailedUpload({
81→					sessionId: item.sessionId,
82→					transcriptPath: item.transcriptPath,
83→					projectPath: item.projectPath,
84→					source: item.source,
85→					organizationId: item.organizationId,
86→					error,
87→				});
88→			} finally {
89→				completed++;
90→				onItemComplete?.(completed, total);
91→			}
92→		},
93→		{ concurrency, stopOnError: false },
94→	);
95→
96→	return { succeeded, failed, total, errors };
97→}
