  1→import * as p from "@clack/prompts";
  2→import { type AgentAdapter, getAvailableAdapters } from "@rudel/agent-adapters";
  3→import { buildCommand } from "@stricli/core";
  4→import { createApiClient } from "../lib/api-client.js";
  5→import { verifyAuth } from "../lib/auth.js";
  6→import type { BatchUploadItem } from "../lib/batch-upload.js";
  7→import { renderBatchSummary, runBatchUpload } from "../lib/batch-upload-ui.js";
  8→import { getGitInfo } from "../lib/git-info.js";
  9→import { getProjectOrgId, setProjectOrgId } from "../lib/project-config.js";
 10→import { uploadSession } from "../lib/uploader.js";
 11→
 12→async function runEnable(): Promise<void> {
 13→	p.intro("rudel enable");
 14→
 15→	// Verify auth (loads credentials + pings API)
 16→	const auth = await verifyAuth();
 17→	if (!auth.authenticated) {
 18→		p.log.error(auth.message);
 19→		p.outro("Run `rudel login` to authenticate.");
 20→		process.exitCode = 1;
 21→		return;
 22→	}
 23→
 24→	const { credentials } = auth;
 25→
 26→	// Fetch user's organizations
 27→	const client = createApiClient(credentials);
 28→	let orgs: { id: string; name: string; slug: string }[];
 29→	try {
 30→		orgs = await client.listMyOrganizations();
 31→	} catch {
 32→		p.log.error("Failed to fetch organizations. Check your connection.");
 33→		process.exitCode = 1;
 34→		return;
 35→	}
 36→
 37→	if (orgs.length === 0) {
 38→		p.log.error("No organizations found.");
 39→		p.outro("Create one at app.rudel.ai first.");
 40→		process.exitCode = 1;
 41→		return;
 42→	}
 43→
 44→	// Check if already configured for this project
 45→	const cwd = process.cwd();
 46→	const existingOrgId = await getProjectOrgId(cwd);
 47→	const existingOrg = existingOrgId
 48→		? orgs.find((o) => o.id === existingOrgId)
 49→		: undefined;
 50→
 51→	let selectedOrgId: string;
 52→
 53→	const [firstOrg] = orgs;
 54→	if (orgs.length === 1 && firstOrg) {
 55→		selectedOrgId = firstOrg.id;
 56→		p.log.info(`Using organization: ${firstOrg.name}`);
 57→	} else if (existingOrg) {
 58→		p.log.info(`Currently configured for: ${existingOrg.name}`);
 59→		selectedOrgId = existingOrg.id;
 60→	} else {
 61→		const selected = await p.select({
 62→			message: "Select an organization for this repository",
 63→			options: orgs.map((org) => ({
 64→				value: org.id,
 65→				label: org.name,
 66→				hint: org.slug,
 67→			})),
 68→		});
 69→
 70→		if (p.isCancel(selected)) {
 71→			p.cancel("Setup cancelled.");
 72→			return;
 73→		}
 74→
 75→		selectedOrgId = selected;
 76→		const selectedOrg = orgs.find((o) => o.id === selected);
 77→		if (selectedOrg) {
 78→			p.log.success(`Selected: ${selectedOrg.name}`);
 79→		}
 80→	}
 81→
 82→	await setProjectOrgId(cwd, selectedOrgId);
 83→
 84→	// Detect available agents and install hooks
 85→	const adapters = getAvailableAdapters();
 86→	let adaptersToEnable: AgentAdapter[];
 87→
 88→	if (adapters.length > 1) {
 89→		const agentOptions = adapters.map((a) => ({
 90→			value: a,
 91→			label: a.name,
 92→			hint: a.isHookInstalled() ? "already enabled" : undefined,
 93→		}));
 94→		const selectedAdapters = await p.multiselect({
 95→			message: "Select agents to enable auto-upload for",
 96→			options: agentOptions,
 97→			initialValues: adapters,
 98→			required: true,
 99→		});
100→
101→		if (p.isCancel(selectedAdapters)) {
102→			p.cancel("Setup cancelled.");
103→			return;
104→		}
105→		adaptersToEnable = selectedAdapters;
106→	} else {
107→		adaptersToEnable = adapters;
108→	}
109→
110→	for (const adapter of adaptersToEnable) {
111→		if (adapter.isHookInstalled()) {
112→			p.log.info(
113→				`${adapter.name}: Auto-upload hook is already enabled. Organization updated.`,
114→			);
115→		} else {
116→			adapter.installHook();
117→			p.log.success(
118→				`${adapter.name}: Auto-upload hook enabled in ${adapter.getHookConfigPath()}`,
119→			);
120→		}
121→	}
122→
123→	// Check for existing sessions to upload from all enabled agents
124→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
125→	let totalFailed = 0;
126→
127→	for (const adapter of adaptersToEnable) {
128→		const sessions = await adapter.findProjectSessions(cwd);
129→		if (sessions.length === 0) continue;
130→
131→		const shouldUpload = await p.confirm({
132→			message: `Found ${sessions.length} previous ${adapter.name} session(s). Upload them now?`,
133→			initialValue: false,
134→		});
135→
136→		if (p.isCancel(shouldUpload) || !shouldUpload) continue;
137→
138→		const gitInfo = await getGitInfo(cwd);
139→
140→		const items: BatchUploadItem[] = sessions.map((session) => ({
141→			sessionId: session.sessionId,
142→			label: session.sessionId,
143→			transcriptPath: session.transcriptPath,
144→			projectPath: session.projectPath,
145→			source: adapter.source,
146→			organizationId: selectedOrgId,
147→		}));
148→
149→		const summary = await runBatchUpload({
150→			items,
151→			label: `Uploading ${adapter.name} sessions...`,
152→			upload: async (item, onRetry) => {
153→				const session = sessions.find((s) => s.sessionId === item.sessionId);
154→				if (!session) {
155→					return { success: false, error: "Session not found" };
156→				}
157→				const request = await adapter.buildUploadRequest(session, {
158→					gitInfo,
159→					organizationId: selectedOrgId,
160→				});
161→				return uploadSession(request, {
162→					endpoint,
163→					token: credentials.token,
164→					onRetry,
165→				});
166→			},
167→		});
168→
169→		renderBatchSummary(summary, { context: adapter.name });
170→		totalFailed += summary.failed;
171→	}
172→
173→	if (totalFailed > 0) {
174→		p.log.info("Run `rudel upload --retry` to retry failed uploads.");
175→	}
176→
177→	p.outro("Done!");
178→
179→	if (totalFailed > 0) {
180→		process.exitCode = 1;
181→	}
182→}
183→
184→export const enableCommand = buildCommand({
185→	loader: async () => ({ default: runEnable }),
186→	parameters: {},
187→	docs: {
188→		brief: "Enable automatic session upload for coding agents",
189→	},
190→});
