 1→import {
 2→	getAdapter,
 3→	getAvailableAdapters,
 4→	groupProjectsForCwd,
 5→	type ScannedProject,
 6→} from "@rudel/agent-adapters";
 7→import { buildCommand } from "@stricli/core";
 8→
 9→async function runListSessions(): Promise<void> {
10→	const adapters = getAvailableAdapters();
11→	const allProjects: ScannedProject[] = [];
12→	for (const adapter of adapters) {
13→		const projects = await adapter.scanAllSessions();
14→		allProjects.push(...projects);
15→	}
16→
17→	if (allProjects.length === 0) {
18→		console.log("No projects with sessions found.");
19→		return;
20→	}
21→
22→	const cwd = process.cwd();
23→	const grouped = groupProjectsForCwd(allProjects, cwd);
24→
25→	const lines: string[] = [];
26→
27→	for (const proj of grouped.current) {
28→		const name = getAdapter(proj.source).name;
29→		lines.push(
30→			`[${name}] ${proj.displayPath} (${proj.sessionCount} sessions) [current]`,
31→		);
32→	}
33→
34→	for (const sub of grouped.subfolders) {
35→		const name = getAdapter(sub.source).name;
36→		const relative = sub.projectPath.slice(cwd.length + 1);
37→		lines.push(`  [${name}] ${relative} (${sub.sessionCount} sessions)`);
38→	}
39→
40→	for (const other of grouped.others) {
41→		const name = getAdapter(other.source).name;
42→		lines.push(
43→			`[${name}] ${other.displayPath} (${other.sessionCount} sessions)`,
44→		);
45→	}
46→
47→	const totalSessions = allProjects.reduce((s, p) => s + p.sessionCount, 0);
48→	console.log(`${allProjects.length} projects, ${totalSessions} sessions\n`);
49→	for (const line of lines) {
50→		console.log(line);
51→	}
52→}
53→
54→export const listSessionsCommand = buildCommand({
55→	loader: async () => ({ default: runListSessions }),
56→	parameters: {},
57→	docs: {
58→		brief: "List session files that would appear in the upload picker",
59→	},
60→});
