 44→	test("uploads a session via uploadSession to the local API", async () => {
 45→		expect(bearerToken).toBeTruthy();
 46→
 47→		const testId = `cli_api_test_${Date.now()}`;
 48→		const request: IngestSessionInput = {
 49→			source: "claude_code",
 50→			sessionId: testId,
 51→			projectPath: "/test/cli-api-upload",
 52→			repository: "test-repo",
 53→			gitBranch: "main",
 54→			gitSha: "abc123",
 55→			tag: "tests",
 56→			content: "cli api integration test content",
 57→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
 58→		};
 59→
 60→		// Retry up to 3 times — Bun may kill the server as a "dangling process"
 61→		// and the restarted server's ClickHouse connection can be slow to warm up.
 62→		// Each attempt has a per-call timeout so a hanging request doesn't
 63→		// consume the entire test timeout and block retries.
 64→		// Note: uploadSession itself retries up to 3 times with exponential backoff
 65→		// (1s, 2s delays), so a full internal cycle can take ~20s. The per-attempt
 66→		// timeout must exceed this to avoid cutting off mid-retry.
 67→		let result = { success: false, error: "not attempted" } as Awaited<
 68→			ReturnType<typeof uploadSession>
 69→		>;
 70→		for (let attempt = 0; attempt < 3; attempt++) {
 71→			result = await Promise.race([
 72→				uploadSession(request, {
 73→					endpoint: server.rpcUrl,
 74→					token: bearerToken,
 75→				}),
 76→				Bun.sleep(25_000).then(
 77→					() =>
 78→						({ success: false, error: "attempt timed out" }) as Awaited<
 79→							ReturnType<typeof uploadSession>
 80→						>,
 81→				),
 82→			]);
 83→			if (result.success) break;
 84→			await server.ensureAlive();
 85→			await Bun.sleep(1000);
 86→		}
 87→
 88→		if (!result.success) {
 89→			throw new Error(`uploadSession failed after 3 attempts: ${result.error}`);
 90→		}
 91→		expect(result.status).toBe(200);
 92→	}, 90_000);
