  1→import { afterAll, describe, expect, test } from "bun:test";
  2→import { getAdapter } from "@rudel/agent-adapters";
  3→import type { IngestSessionInput } from "@rudel/api-routes";
  4→import { createClickHouseExecutor } from "../clickhouse.js";
  5→
  6→const testId = `api_test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  7→
  8→const baseExecutor = createClickHouseExecutor({
  9→	url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 10→	username:
 11→		process.env.CLICKHOUSE_USERNAME || process.env.CLICKHOUSE_USER || "default",
 12→	password: process.env.CLICKHOUSE_PASSWORD || "",
 13→	database: "default",
 14→});
 15→
 16→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 17→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
 18→// async_insert=0 forces synchronous insert so data is immediately queryable.
 19→const executor: typeof baseExecutor = {
 20→	...baseExecutor,
 21→	async insert(params) {
 22→		const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
 23→		await baseExecutor.execute(
 24→			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
 25→		);
 26→	},
 27→};
 28→
 29→afterAll(() => {
 30→	// Fire-and-forget: ClickHouse Cloud DELETE mutations are slow
 31→	executor
 32→		.execute(`DELETE FROM rudel.claude_sessions WHERE session_id = '${testId}'`)
 33→		.catch(() => {});
 34→});
 35→
 36→async function waitForRow(
 37→	sessionId: string,
 38→	timeoutMs = 30000,
 39→	intervalMs = 2000,
 40→): Promise<
 41→	Array<{
 42→		session_id: string;
 43→		project_path: string;
 44→		repository: string;
 45→		tag: string;
 46→		user_id: string;
 47→		organization_id: string;
 48→	}>
 49→> {
 50→	const start = Date.now();
 51→	while (Date.now() - start < timeoutMs) {
 52→		try {
 53→			const results = await executor.query<{
 54→				session_id: string;
 55→				project_path: string;
 56→				repository: string;
 57→				tag: string;
 58→				user_id: string;
 59→				organization_id: string;
 60→			}>(
 61→				`SELECT session_id, project_path, repository, tag, user_id, organization_id FROM rudel.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
 62→			);
 63→			if (results.length > 0) return results;
 64→		} catch {
 65→			// Transient ClickHouse errors (e.g. S3 storage) - retry
 66→		}
 67→		await new Promise((r) => setTimeout(r, intervalMs));
 68→	}
 69→	return [];
 70→}
 71→
 72→describe("ingestSession", () => {
 73→	test("ingests a session into ClickHouse and reads it back", async () => {
 74→		const input: IngestSessionInput = {
 75→			source: "claude_code",
 76→			sessionId: testId,
 77→			projectPath: "/test/api-ingest",
 78→			repository: "test-repo",
 79→			gitBranch: "feature-branch",
 80→			gitSha: "deadbeef",
 81→			tag: "tests",
 82→			content: "integration test content",
 83→			subagents: [{ agentId: "sub-1", content: "subagent content" }],
 84→		};
 85→
 86→		// ClickHouse Cloud can silently drop inserts or throw race condition
 87→		// errors (code 236). Retry the insert+read cycle with exponential backoff.
 88→		let results: Awaited<ReturnType<typeof waitForRow>> = [];
 89→		for (let attempt = 0; attempt < 5; attempt++) {
 90→			try {
 91→				const adapter = getAdapter(input.source);
 92→				await adapter.ingest(executor, input, {
 93→					userId: "test_user",
 94→					organizationId: "test_org",
 95→				});
 96→			} catch {
 97→				await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
 98→				continue;
 99→			}
100→			results = await waitForRow(testId);
101→			if (results.length > 0) break;
102→		}
103→
104→		expect(results).toHaveLength(1);
105→		expect(results[0]?.session_id).toBe(testId);
106→		expect(results[0]?.project_path).toBe("/test/api-ingest");
107→		expect(results[0]?.repository).toBe("test-repo");
108→		expect(results[0]?.tag).toBe("tests");
109→		expect(results[0]?.user_id).toBe("test_user");
110→		expect(results[0]?.organization_id).toBe("test_org");
111→	}, 120000);
112→});
